int maximum(int a, int b, int c) {
    int k;
    if (b >= a)
        k = b;
    else
        k = a;

    if (c >= k)
        return c;
    else
        return k;
}

void needle_cuda_shared_1(
    const int* referrence,
    int* matrix_cuda,
    int cols,
    int penalty,
    int i,
    int block_width,
    int worksize,
    int offset_r,
    int offset_c)
{
    int bx = get_block_id(0);
    int tx = get_local_id(0);

    int b_index_x = bx;
    int b_index_y = i - 1 - bx;

    int base_index = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;
    int index   = base_index + tx + (cols + 1);
    int index_n   = base_index + tx + 1;
    int index_w   = base_index + cols;
    int index_nw =  base_index;

    // Declare local arrays with fixed size based on BLOCK_SIZE macro
    int temp[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int ref[BLOCK_SIZE * BLOCK_SIZE];

    if (0 == tx)
        temp[0] = matrix_cuda[index_nw];

    for (int ty = 0; ty < BLOCK_SIZE; ty++)
        ref[ty * BLOCK_SIZE + tx] = referrence[index + cols * ty];

    barrier(CLK_LOCAL_MEM_FENCE);

    temp[(tx + 1) * (BLOCK_SIZE + 1)] = matrix_cuda[index_w + cols * tx];

    barrier(CLK_LOCAL_MEM_FENCE);

    temp[tx + 1] = matrix_cuda[index_n];

    barrier(CLK_LOCAL_MEM_FENCE);

    for (int m = 0; m < BLOCK_SIZE; m++) {
        if (m >= tx) {
            int t_index_x = tx + 1;
            int t_index_y = m - tx + 1;

            int val_diag = temp[(t_index_y - 1) * (BLOCK_SIZE + 1) + (t_index_x - 1)] + ref[(t_index_y - 1) * BLOCK_SIZE + (t_index_x - 1)];
            int val_left = temp[t_index_y * (BLOCK_SIZE + 1) + (t_index_x - 1)] - penalty;
            int val_up   = temp[(t_index_y - 1) * (BLOCK_SIZE + 1) + t_index_x] - penalty;

            temp[t_index_y * (BLOCK_SIZE + 1) + t_index_x] = maximum(val_diag, val_left, val_up);
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
        if (m >= tx) {
            int t_index_x = tx + BLOCK_SIZE - m;
            int t_index_y = BLOCK_SIZE - tx;

            int val_diag = temp[(t_index_y - 1) * (BLOCK_SIZE + 1) + (t_index_x - 1)] + ref[(t_index_y - 1) * BLOCK_SIZE + (t_index_x - 1)];
            int val_left = temp[t_index_y * (BLOCK_SIZE + 1) + (t_index_x - 1)] - penalty;
            int val_up   = temp[(t_index_y - 1) * (BLOCK_SIZE + 1) + t_index_x] - penalty;

            temp[t_index_y * (BLOCK_SIZE + 1) + t_index_x] = maximum(val_diag, val_left, val_up);
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    for (int ty = 0; ty < BLOCK_SIZE; ty++)
        matrix_cuda[index + ty * cols] = temp[(ty + 1) * (BLOCK_SIZE + 1) + (tx + 1)];
}

